"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";

const BASE_URL = "http://localhost:5000";

const ClaimDetailsPage = () => {
  const { id } = useParams();
  const router = useRouter();

  const [claim, setClaim] = useState(null);
  const [loading, setLoading] = useState(true);

  // ================= FETCH CLAIM =================
  useEffect(() => {
    if (!id) return;

    const fetchClaim = async () => {
      try {
        const token = localStorage.getItem("accessToken");

        const res = await fetch(`${BASE_URL}/admin/claim/${id}`, {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        });

        if (!res.ok) throw new Error("Failed to load claim");

        const data = await res.json();
        setClaim(data);
      } catch (err) {
        console.error("Fetch error:", err);
      } finally {
        setLoading(false);
      }
    };

    fetchClaim();
  }, [id]);

  // ================= APPROVE =================
  const handleApprove = async () => {
    try {
      const token = localStorage.getItem("accessToken");

      const res = await fetch(`${BASE_URL}/admin/approveItem/${id}`, {
        method: "PUT",
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      if (!res.ok) throw new Error("Approve failed");

      alert("Claim Approved");
      router.push("/admin/claimsreview");
    } catch (err) {
      console.error(err);
      alert("Failed to approve");
    }
  };

  // ================= REJECT =================
  const handleReject = async () => {
    try {
      const token = localStorage.getItem("accessToken");

      const res = await fetch(`${BASE_URL}/admin/rejectItem/${id}`, {
        method: "PUT",
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      if (!res.ok) throw new Error("Reject failed");

      alert("Claim Rejected");
      router.push("/admin/claimsreview");
    } catch (err) {
      console.error(err);
      alert("Failed to reject");
    }
  };

  // ================= UI =================
  if (loading) return <p className="p-10">Loading...</p>;
  if (!claim) return <p className="p-10">Claim not found</p>;

  const item = claim.itemId;
  const claimant = claim.claimedBy;
  const poster = claim.postedBy;

  return (
    <div className="max-w-6xl mx-auto p-6 mt-8">
      <h1 className="text-3xl font-bold mb-6">Claim Review</h1>

      <div className="grid md:grid-cols-2 gap-6">
        {/* ================= ITEM DETAILS ================= */}
        <div className="bg-white shadow-lg rounded-xl p-5">
          <h2 className="text-xl font-semibold mb-3">Item Information</h2>

          {/* ITEM PHOTOS */}
          {item?.photos?.length > 0 && (
            <div className="grid grid-cols-3 gap-2 mb-4">
              {item.photos.map((img, i) => (
                <img
                  key={i}
                  src={`${BASE_URL}/uploads/${img}`}
                  alt="Item"
                  className="h-28 w-full object-cover rounded border"
                />
              ))}
            </div>
          )}

          <p className="mb-1">
            <b>Name:</b> {item.itemName}
          </p>
          <p className="mb-1">
            <b>Category:</b> {item.category}
          </p>
          <p className="mb-1">
            <b>Location:</b> {item.location}
          </p>
          <p className="mb-1">
            <b>Description:</b> {item.description}
          </p>

          <div className="mt-3 text-sm text-gray-600">
            <p>
              <b>Status:</b> {item.status}
            </p>
            <p>
              <b>Verified:</b> {item.isVerified ? "Yes" : "No"}
            </p>
          </div>
        </div>

        {/* ================= CLAIM DETAILS ================= */}
        <div className="bg-white shadow-lg rounded-xl p-5">
          <h2 className="text-xl font-semibold mb-3">Claim Information</h2>

          <p className="mb-1">
            <b>Claimed By:</b> {claimant?.name}
          </p>
          <p className="mb-3">
            <b>Email:</b> {claimant?.email}
          </p>

          <p className="mb-1">
            <b>Posted By:</b> {poster?.name}
          </p>
          <p className="mb-3">
            <b>Poster Email:</b> {poster?.email}
          </p>

          <h3 className="font-semibold mb-2">Proof Description</h3>
          <p className="bg-gray-100 p-3 rounded mb-4">
            {claim.proofDescription}
          </p>

          {/* CLAIM PROOF PHOTOS */}
          {claim.photos?.length > 0 && (
            <>
              <h3 className="font-semibold mb-2">Proof Photos</h3>
              <div className="grid grid-cols-3 gap-2">
                {claim.photos.map((img, i) => (
                  <img
                    key={i}
                    src={`${BASE_URL}/uploads/${img}`}
                    alt="Proof"
                    className="h-28 w-full object-cover rounded border"
                  />
                ))}
              </div>
            </>
          )}

          <div className="mt-4 text-sm text-gray-600">
            <p>
              <b>Claim Status:</b> {claim.status}
            </p>
          </div>
        </div>
      </div>

      {/* ================= ACTION BUTTONS ================= */}
      <div className="flex justify-center gap-6 mt-10">
        <button
          onClick={handleApprove}
          className="bg-green-600 text-white px-10 py-3 rounded-lg hover:bg-green-700 transition"
        >
          Approve Claim
        </button>

        <button
          onClick={handleReject}
          className="bg-red-600 text-white px-10 py-3 rounded-lg hover:bg-red-700 transition"
        >
          Reject Claim
        </button>
      </div>
    </div>
  );
};

export default ClaimDetailsPage;
